 / / // ||/ / // / / / / ||/ / | / // / / 
 / /____/ / //____/ / | / //____/ / / /____/ / / / | / | / ((___/ / 
' print(art) return bytearray(input('Please give me the flag: ').encode()) enc = [ 115, 121, 116, 114, 110, 76, 37, 96, 88, 116, 113, 112, 36, 97, 65, 125, 103, 37, 96, 114, 125, 65, 39, 112, 70, 112, 118, 37, 123, 113, 69, 79, 82, 84, 89, 84, 77, 76, 36, 112, 99, 112, 36, 65, 39, 116, 97, 36, 102, 86, 37, 37, 36, 104] data = hello() for i in range(len(data)): data[i] = data[i] ^ 21 if bytearray(enc) == data: print('WOW!!') else: print('I believe you can do it!') input('To be continue...') 这里发现，将env的每个值异或21后打印即可。 EXP如下： enc = [115,121,116,114,110,76,37,96,88,116,113,112,36,97,65,125,103,37,96,114,125,65,39,112,70,112,118,37,123,113,69,79,82,84,89,84,77,76,36,112,99, 112,36,65,39,116,97,36,102,86,37,37,36,104] for i in range(0,len(enc)): enc[i] = enc[i] ^ 21 print(bytearray(enc)) 输出如下： bytearray(b'flag{Y0uMade1tThr0ughT2eSec0ndPZGALAXY1eve1T2at1sC001}')
